---scenes config---
# build_scene_shorts.ps1  (PS 5.1 safe: ASCII-only)
# Per-scene AI illustrations (demo.mp4 style: one distinct image per scene).
# Reads scenes/s{NN}_{i}.png. Renders only shorts whose full image set exists.
# Same Zundamon voice + zoompan + bottom kinetic captions as build_ai_shorts.ps1.
param([int]$Speaker = 3, [double]$Speed = 1.1, [double]$Tail = 0.25, [int]$Max = 3, [int]$Only = 0)
$ErrorActionPreference = "Continue"
$root = "C:\aaa\video-assets"; $sc = Join-Path $root "ai\scenes"
$scriptsDir = "C:\aaa\scripts\shorts"; $outDir = Join-Path $root "shorts"
$pkg = "$env:LOCALAPPDATA\Microsoft\WinGet\Packages"
$ff = (Get-ChildItem $pkg -Recurse -Filter ffmpeg.exe -EA SilentlyContinue | Select-Object -First 1).FullName
$fp = (Get-ChildItem $pkg -Recurse -Filter ffprobe.exe -EA SilentlyContinue | Select-Object -First 1).FullName
$vvUp = $false; try { Invoke-RestMethod "http://localhost:50021/version" -TimeoutSec 3 | Out-Null; $vvUp = $true } catch {}
if (-not $vvUp) { Write-Error "VOICEVOX not up"; exit 1 }
$all = @(); foreach ($f in (Get-ChildItem $scriptsDir -Filter "batch*.json" | Sort-Object Name)) { (Get-Content $f.FullName -Raw -Encoding UTF8 | ConvertFrom-Json) | ForEach-Object { $all += $_ } }
$kin = '{\fad(120,80)\fscx80\fscy80\t(0,200,\fscx104\fscy104)\t(200,300,\fscx100\fscy100)}'
function Synth($t, $w) { $e = [uri]::EscapeDataString($t); $q = Invoke-RestMethod -Method Post -Uri "http://localhost:50021/audio_query?speaker=$Speaker&text=$e" -TimeoutSec 30; $q.speedScale = $Speed; $b = $q | ConvertTo-Json -Depth 60 -Compress; Invoke-WebRequest -Method Post -Uri "http://localhost:50021/synthesis?speaker=$Speaker" -ContentType "application/json" -Body $b -OutFile $w -TimeoutSec 90 | Out-Null }
function WrapJ([string]$t, [int]$m) { $o = ""; $l = ""; foreach ($c in $t.ToCharArray()) { $l += $c; if ($l.Length -ge $m -and ($c -eq [char]0x3001 -or $c -eq [char]0x3002)) { $o += $l + "\N"; $l = "" } elseif ($l.Length -ge ($m + 4)) { $o += $l + "\N"; $l = "" } }; $r = $o + $l; $cm = [char]0x3001; $pd = [char]0x3002; $r = $r -replace ("\\N" + $cm), ($cm + "\N"); $r = $r -replace ("\\N" + $pd), ($pd + "\N"); return $r }
function AT([double]$t) { $h = [math]::Floor($t / 3600); $m = [math]::Floor(($t % 3600) / 60); $s = $t - ($h * 3600) - ($m * 60); return ("{0}:{1:00}:{2:00.00}" -f $h, $m, $s) }
function RenderOne($script, $num) {
  $tag = "{0:00}" -f $num
  for ($i = 1; $i -le $script.scenes.Count; $i++) { if (-not (Test-Path (Join-Path $sc ("s{0:00}_{1}.png" -f $num, $i)))) { "skip short $num (missing scene image $i)"; return } }
  $work = Join-Path $root ("scene_build\" + $tag); if (Test-Path $work) { Remove-Item $work -Recurse -Force -EA SilentlyContinue }; New-Item -ItemType Directory -Force -Path $work | Out-Null
  $segs = @(); $ev = @(); $cur = 0.0; $i = 0
  foreach ($s in $script.scenes) {
    $i++; $img = Join-Path $sc ("s{0:00}_{1}.png" -f $num, $i); $wav = Join-Path $work ("a$i.wav"); $seg = Join-Path $work ("seg{0:00}.mp4" -f $i)
    Synth $s.narration $wav
    $dur = [double](& $fp -v error -show_entries format=duration -of "csv=p=0" $wav) + $Tail; $fr = [int][math]::Ceiling($dur * 30)
    if ($i % 2 -eq 1) { $z = "min(zoom+0.0005\,1.06)" } else { $z = "if(eq(on\,0)\,1.06\,max(zoom-0.0005\,1.0))" }
    $fc = "[0:v]scale=1188:2112:force_original_aspect_ratio=increase,crop=1188:2112,zoompan=z=${z}:d=${fr}:x=iw/2-(iw/zoom/2):y=ih/2-(ih/zoom/2):s=1080x1920:fps=30,setsar=1[v]"
    & $ff -hide_banner -loglevel error -y -loop 1 -i $img -i $wav -filter_complex $fc -map "[v]" -map "1:a" -t $dur -c:v libx264 -pix_fmt yuv420p -c:a aac -b:a 192k $seg
    if ($LASTEXITCODE -ne 0) { Write-Error "seg fail $num/$i"; return }
    $segs += ("file '{0}'" -f ("seg{0:00}.mp4" -f $i)); $ev += ("Dialogue: 0,{0},{1},Default,,0,0,0,,{2}" -f (AT $cur), (AT ($cur + $dur)), ($kin + (WrapJ $s.narration 11))); $cur += $dur
  }
  $st = Join-Path $work "segs.txt"; [IO.File]::WriteAllLines($st, $segs, [Text.UTF8Encoding]::new($false))
  & $ff -hide_banner -loglevel error -y -f concat -safe 0 -i $st -c copy (Join-Path $work "j.mp4"); if ($LASTEXITCODE -ne 0) { Write-Error "concat $num"; return }
  $a = @("[Script Info]", "ScriptType: v4.00+", "PlayResX: 1080", "PlayResY: 1920", "WrapStyle: 2", "ScaledBorderAndShadow: yes", "", "[V4+ Styles]", "Format: Name, Fontname, Fontsize, PrimaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding", "Style: Default,Meiryo,60,&H00FFFFFF,&H00141414,&H50000000,-1,0,0,0,100,100,0,0,1,8,3,2,70,70,150,1", "", "[Events]", "Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text")
  [IO.File]::WriteAllText((Join-Path $work "subs.ass"), (($a + $ev) -join "`n") + "`n", [Text.UTF8Encoding]::new($false))
  Push-Location $work; & $ff -hide_banner -loglevel error -y -i "j.mp4" -vf "subtitles=subs.ass" -c:v libx264 -pix_fmt yuv420p -c:a copy (Join-Path $outDir ("short_{0}.mp4" -f $tag)); $e = $LASTEXITCODE; Pop-Location
  if ($e -eq 0) { "OK short $tag ($([math]::Round($cur,1))s)" } else { Write-Error "burn $num" }
}
$idx = 0; foreach ($s in $all) { $idx++; if ($Only -gt 0) { if ($idx -ne $Only) { continue } } elseif ($idx -gt $Max) { break }; "--- scene-short $idx ---"; try { RenderOne $s $idx } catch { Write-Error "short ${idx}: $($_.Exception.Message)" } }
"SCENE BATCH DONE"
